"""
Parameterized generator for GH396_maidr_297.

Source PR:    https://github.com/xability/maidr/pull/297
Source Issue: https://github.com/xability/maidr/issues/296

Seed varies: renames 'abstract' identifier with suffix across seeds.

Bug: pre-PR state of workspace files contains the bug the PR fixes.
Fix: agent must replicate the PR's changes guided by spec.md.
"""
from __future__ import annotations

import os
from generators.base import TaskGenerator, GeneratedTask


class Generator(TaskGenerator):
    task_id = 'GH396_maidr_297'
    domain = "Real-World GitHub"
    difficulty = "medium"
    languages = ["python"]

    def generate(self, seed: int) -> GeneratedTask:
        tasks_dir = os.path.join(
            os.path.dirname(__file__), "..", "tasks", 'GH396_maidr_297'
        )
        with open(os.path.join(tasks_dir, "spec.md")) as f:
            spec_md = f.read()
        with open(os.path.join(tasks_dir, "brief.md")) as f:
            brief_md = f.read()

        files = self._base_workspace()
        # Apply seed-based renaming to prevent direct memorization
        suffixes = ["", "_alt", "_impl"]
        suffix = suffixes[seed % len(suffixes)]
        if suffix:
            for fpath in list(files.keys()):
                files[fpath] = files[fpath].replace('abstract', 'abstract' + suffix)
        # Deep parameterization — consistent cross-seed variation
        from generators.gh_deep_param import deep_rename_symbols, add_realistic_noise
        files = deep_rename_symbols(files, seed, strategy="mixed")
        files = add_realistic_noise(files, seed, noise_level=0.15)
        return GeneratedTask(
            task_id='GH396_maidr_297',
            seed=seed,
            spec_md=spec_md,
            brief_md=brief_md,
            expected={
                "seed": seed,
                "repo": 'xability/maidr',
                "pr_number": 297,
                "bug_fixed": True,
            },
            workspace_files=files,
            metadata={
                "difficulty": "medium",
                "category": "Real-World GitHub",
                "source_pr": "https://github.com/xability/maidr/pull/297",
            },
        )

    def _base_workspace(self) -> dict[str, str]:
        """Return the pre-PR (buggy) workspace files."""
        return {
            'src/service/chat.ts': "import type { DisplayService } from '@service/display';\nimport type { Maidr } from '@type/grammar';\nimport type { ClaudeVersion, GeminiVersion, GptVersion, Llm, LlmRequest, LlmResponse } from '@type/llm';\nimport type { PromptContext } from './prompts';\nimport { Scope } from '@type/event';\nimport { Api } from '@util/api';\nimport { Svg } from '@util/svg';\nimport { formatSystemPrompt, formatUserPrompt } from './prompts';\n\nexport class ChatService {\n  private readonly display: DisplayService;\n  private readonly models: Record<Llm, LlmModel>;\n\n  public constructor(display: DisplayService, maidr: Maidr) {\n    this.display = display;\n\n    this.models = {\n      GPT: new Gpt(display.plot, maidr, 'gpt-4o'),\n      CLAUDE: new Claude(display.plot, maidr, 'claude-3-7-sonnet-latest'),\n      GEMINI: new Gemini(display.plot, maidr, 'gemini-2.0-flash'),\n    };\n  }\n\n  public async sendMessage(model: Llm, request: LlmRequest): Promise<LlmResponse> {\n    return this.models[model].getLlmResponse(request);\n  }\n\n  public toggle(): void {\n    this.display.toggleFocus(Scope.CHAT);\n  }\n}\n\ninterface LlmModel {\n  getLlmResponse: (request: LlmRequest) => Promise<LlmResponse>;\n}\n\ninterface GptResponse {\n  choices: {\n    message: {\n      content: string;\n    };\n  }[];\n}\n\ninterface ClaudeResponse {\n  content: {\n    text: string;\n  }[];\n}\n\ninterface GeminiResponse {\n  candidates: {\n    content: {\n      parts: {\n        text: string;\n      }[];\n    };\n  }[];\n}\n\nabstract class AbstractLlmModel<T> implements LlmModel {\n  protected readonly svg: HTMLElement;\n  protected readonly json: string;\n\n  private readonly maidrBaseUrl: string;\n  private readonly codeQueryParam: string;\n\n  protected constructor(svg: HTMLElement, maidr: Maidr) {\n    this.svg = svg;\n    this.json = JSON.stringify(maidr);\n\n    this.maidrBaseUrl = 'https://maidr-service.azurewebsites.net/api';\n    this.codeQueryParam = 'I8Aa2PlPspjQ8Hks0QzGyszP8_i2-XJ3bq7Xh8-ykEe4AzFuYn_QWA%3D%3D';\n  }\n\n  public async getLlmResponse(request: LlmRequest): Promise<LlmResponse> {\n    try {\n      const image = await Svg.toBase64(this.svg);\n      const payload = this.getPayload(\n        request.customInstruction,\n        this.json,\n        image,\n        '',\n        request.message,\n      );\n\n      const url = request.clientToken\n        ? this.getMaidrUrl()\n        : this.getApiUrl(request.apiKey);\n\n      const headers = this.getHeaders(request);\n      const response = await Api.post<T>(url, payload, headers);\n      if (!response.success) {\n        return {\n          success: false,\n          error: response.error?.message,\n        };\n      } else if (!response.data) {\n        return {\n          success: false,\n          error: 'Response unavailable',\n        };\n      } else {\n        return this.formatResponse(response.data);\n      }\n    } catch (error) {\n      return {\n        success: false,\n        error: error instanceof Error ? error.message : 'Unknown error occurred',\n      };\n    }\n  }\n\n  private getMaidrUrl(): string {\n    return `${this.maidrBaseUrl}/${this.getEndPoint()}?code=${this.codeQueryParam}`;\n  }\n\n  protected getHeaders(request: LlmRequest): Record<string, string> {\n    const headers: Record<string, string> = {\n      'Content-Type': 'application/json',\n    };\n\n    if (request.clientToken) {\n      headers.Authentication = `${request.email} ${request.clientToken}`;\n    } else {\n      headers.Authorization = `Bearer ${request.apiKey}`;\n    }\n\n    return headers;\n  }\n\n  protected abstract getApiUrl(apiKey?: string): string;\n\n  protected abstract getEndPoint(): string;\n\n  protected abstract getPayload(\n    customInstruction: string,\n    maidrJson: string,\n    image: string,\n    currentText: string,\n    message: string,\n  ): string;\n\n  protected abstract formatResponse(response: T): LlmResponse;\n}\n\nclass Gpt extends AbstractLlmModel<GptResponse> {\n  private readonly version: GptVersion;\n\n  public constructor(svg: HTMLElement, maidr: Maidr, version: GptVersion) {\n    super(svg, maidr);\n    this.version = version;\n  }\n\n  protected getApiUrl(): string {\n    return 'https://api.openai.com/v1/chat/completions';\n  }\n\n  protected getEndPoint(): string {\n    return 'openai';\n  }\n\n  protected getPayload(\n    customInstruction: string,\n    maidrJson: string,\n    image: string,\n    currentPositionText: string,\n    message: string,\n  ): string {\n    const context: PromptContext = {\n      customInstruction,\n      maidrJson,\n      currentPositionText,\n      message,\n    };\n\n    return JSON.stringify({\n      model: this.version,\n      max_tokens: 1000,\n      messages: [\n        {\n          role: 'system',\n          content: formatSystemPrompt(customInstruction),\n        },\n        {\n          role: 'user',\n          content: [\n            {\n              type: 'text',\n              text: formatUserPrompt(context),\n            },\n            {\n              type: 'image_url',\n              image_url: {\n                url: image,\n              },\n            },\n          ],\n        },\n      ],\n    });\n  }\n\n  protected formatResponse(response: GptResponse): LlmResponse {\n    if (response.choices.length === 0) {\n      return {\n        success: false,\n        error: 'Invalid response format',\n      };\n    }\n\n    return {\n      success: true,\n      data: response.choices[0].message.content,\n    };\n  }\n\n  protected getHeaders(request: LlmRequest): Record<string, string> {\n    const headers = super.getHeaders(request);\n    return headers;\n  }\n}\n\nclass Claude extends AbstractLlmModel<ClaudeResponse> {\n  private readonly version: ClaudeVersion;\n\n  public constructor(svg: HTMLElement, maidr: Maidr, version: ClaudeVersion) {\n    super(svg, maidr);\n    this.version = version;\n  }\n\n  protected getApiUrl(): string {\n    return 'https://api.anthropic.com';\n  }\n\n  protected getEndPoint(): string {\n    return 'claude';\n  }\n\n  protected getPayload(\n    customInstruction: string,\n    maidrJson: string,\n    image: string,\n    currentPositionText: string,\n    message: string,\n  ): string {\n    const context: PromptContext = {\n      customInstruction,\n      maidrJson,\n      currentPositionText,\n      message,\n    };\n\n    return JSON.stringify({\n      anthropic_version: this.version,\n      max_tokens: 256,\n      messages: [\n        {\n          role: 'user',\n          content: [\n            {\n              type: 'image',\n              source: {\n                type: 'base64',\n                media_type: 'image/jpeg',\n                data: image,\n              },\n            },\n            {\n              type: 'text',\n              text: `${formatSystemPrompt(customInstruction)}\\n\\n${formatUserPrompt(context)}`,\n            },\n          ],\n        },\n      ],\n    });\n  }\n\n  protected formatResponse(response: ClaudeResponse): LlmResponse {\n    if (response.content.length === 0) {\n      return {\n        success: false,\n        error: 'Invalid response format',\n      };\n    }\n\n    return {\n      success: true,\n      data: response.content[0].text,\n    };\n  }\n\n  protected getHeaders(request: LlmRequest): Record<string, string> {\n    const headers = super.getHeaders(request);\n    headers['anthropic-version'] = this.version;\n    return headers;\n  }\n}\n\nclass Gemini extends AbstractLlmModel<GeminiResponse> {\n  private readonly version: GeminiVersion;\n\n  public constructor(svg: HTMLElement, maidr: Maidr, version: GeminiVersion) {\n    super(svg, maidr);\n    this.version = version;\n  }\n\n  protected getApiUrl(apiKey: string): string {\n    if (!apiKey) {\n      throw new Error('API key is required for Gemini API');\n    }\n    return `https://generativelanguage.googleapis.com/v1beta/models/${this.version}:generateContent?key=${apiKey}`;\n  }\n\n  protected getEndPoint(): string {\n    return 'gemini';\n  }\n\n  protected getPayload(\n    customInstruction: string,\n    maidrJson: string,\n    image: string,\n    currentPositionText: string,\n    message: string,\n  ): string {\n    const context: PromptContext = {\n      customInstruction,\n      maidrJson,\n      currentPositionText,\n      message,\n    };\n\n    return JSON.stringify({\n      generationConfig: {},\n      safetySettings: [],\n      contents: [\n        {\n          role: 'user',\n          parts: [\n            {\n              text: formatSystemPrompt(customInstruction),\n            },\n          ],\n        },\n        {\n          role: 'user',\n          parts: [\n            {\n              text: formatUserPrompt(context),\n            },\n            {\n              inlineData: {\n                data: image.split(',')[1],\n                mimeType: 'image/svg+xml',\n              },\n            },\n          ],\n        },\n      ],\n    });\n  }\n\n  protected formatResponse(response: GeminiResponse): LlmResponse {\n    if (response.candidates.length === 0) {\n      return {\n        success: false,\n        error: 'Invalid response format',\n      };\n    }\n\n    return {\n      success: true,\n      data: response.candidates[0].content.parts[0].text,\n    };\n  }\n\n  protected getHeaders(request: LlmRequest): Record<string, string> {\n    const headers = super.getHeaders(request);\n    // Gemini uses API key in URL, so we don't need to add it to headers\n    delete headers.Authorization;\n    return headers;\n  }\n}\n",
            'src/service/prompts.ts': "/**\n * Prompt templates and constants for LLM interactions\n */\n\nexport const SYSTEM_PROMPT = `You are an expert accessibility assistant specializing in describing statistical visualizations to blind users. Your role is to:\n1. Provide clear, concise, and accurate descriptions of charts and graphs\n2. Focus on the most important patterns and insights\n3. Use accessible language that assumes basic statistical knowledge\n4. Structure your responses in a logical, easy-to-follow manner\n5. Highlight key trends, outliers, and relationships in the data\n6. Provide context and interpretation when relevant`;\n\nexport const USER_PROMPT_TEMPLATE = `I need your help understanding this statistical visualization. Here's what I have:\n\n1. Raw data in JSON format: \\n{maidrJson}\\n\n2. Current selected point: {currentPositionText}\n\nPlease help me understand: {message}\n\nFocus on providing a clear, structured response that helps me understand the key insights from this visualization.`;\n\nexport interface PromptContext {\n  customInstruction: string;\n  maidrJson: string;\n  currentPositionText: string;\n  message: string;\n}\n\nexport function formatSystemPrompt(customInstruction: string): string {\n  return `${SYSTEM_PROMPT}\\n\\n${customInstruction}`;\n}\n\nexport function formatUserPrompt(context: PromptContext): string {\n  return USER_PROMPT_TEMPLATE\n    .replace('{maidrJson}', context.maidrJson)\n    .replace('{currentPositionText}', context.currentPositionText)\n    .replace('{message}', context.message);\n}\n",
            'src/type/llm.ts': "import type { Status } from './event';\n\nexport type Llm =\n  | 'GPT'\n  | 'CLAUDE'\n  | 'GEMINI';\n\nexport type GptVersion = 'gpt-4o' | 'gpt-4o-mini' | 'gpt-4.1' | 'o1-mini' | 'o3' | 'o4-mini';\nexport type ClaudeVersion = 'claude-3-5-haiku-latest' | 'claude-3-5-sonnet-latest' | 'claude-3-7-sonnet-latest';\nexport type GeminiVersion = 'gemini-2.0-flash' | 'gemini-2.0-flash-lite' | 'gemini-2.5-flash-preview-04-17' | 'gemini-2.5-pro-preview-05-06';\n\nexport type LlmVersion = GptVersion | ClaudeVersion | GeminiVersion;\n\nexport interface LlmRequest {\n  message: string;\n  customInstruction: string;\n  expertise: string;\n  apiKey?: string;\n  email?: string;\n  clientToken?: string;\n}\n\nexport interface LlmResponse {\n  success: boolean;\n  data?: string;\n  error?: string;\n}\n\nexport interface Message {\n  id: string;\n  text: string;\n  isUser: boolean;\n  model?: Llm;\n  timestamp: string;\n  status: Status;\n}\n\nexport interface LlmModelSettings {\n  name: string;\n  apiKey: string;\n  enabled: boolean;\n  version: LlmVersion;\n}\n",
            'src/ui/pages/Settings.tsx': 'import type { Llm, LlmVersion } from \'@type/llm\';\nimport type { AriaMode, GeneralSettings, LlmModelSettings, LlmSettings } from \'@type/settings\';\nimport { Check as CheckIcon } from \'@mui/icons-material\';\nimport {\n  Button,\n  Dialog,\n  DialogActions,\n  DialogContent,\n  Divider,\n  FormControl,\n  FormControlLabel,\n  Grid,\n  MenuItem,\n  Radio,\n  RadioGroup,\n  Select,\n  Slider,\n  Switch,\n  TextareaAutosize,\n  TextField,\n  Typography,\n} from \'@mui/material\';\nimport { useViewModel } from \'@state/hook/useViewModel\';\nimport React, { useEffect, useId, useState } from \'react\';\n\ntype GptVersion = \'gpt-4o\' | \'gpt-4o-mini\' | \'gpt-4.1\' | \'o1-mini\' | \'o3\' | \'o4-mini\';\ntype ClaudeVersion = \'claude-3-5-haiku-latest\' | \'claude-3-5-sonnet-latest\' | \'claude-3-7-sonnet-latest\';\ntype GeminiVersion = \'gemini-2.0-flash\' | \'gemini-2.0-flash-lite\' | \'gemini-2.5-flash-preview-04-17\' | \'gemini-2.5-pro-preview-05-06\';\n\ninterface ModelConfig<T extends LlmVersion> {\n  default: T;\n  options: readonly T[];\n  labels: Record<T, string>;\n}\n\ninterface ModelVersions {\n  GPT: ModelConfig<GptVersion>;\n  CLAUDE: ModelConfig<ClaudeVersion>;\n  GEMINI: ModelConfig<GeminiVersion>;\n}\n\nconst MODEL_VERSIONS: ModelVersions = {\n  GPT: {\n    default: \'gpt-4o\',\n    options: [\'gpt-4o\', \'gpt-4o-mini\', \'gpt-4.1\', \'o1-mini\', \'o3\', \'o4-mini\'] as const,\n    labels: {\n      \'gpt-4o\': \'GPT-4o\',\n      \'gpt-4o-mini\': \'GPT-4o Mini\',\n      \'gpt-4.1\': \'GPT-4.1\',\n      \'o1-mini\': \'o1-mini\',\n      \'o3\': \'o3\',\n      \'o4-mini\': \'o4-mini\',\n    },\n  },\n  CLAUDE: {\n    default: \'claude-3-7-sonnet-latest\',\n    options: [\'claude-3-5-haiku-latest\', \'claude-3-5-sonnet-latest\', \'claude-3-7-sonnet-latest\'] as const,\n    labels: {\n      \'claude-3-5-haiku-latest\': \'Claude 3.5 Haiku\',\n      \'claude-3-5-sonnet-latest\': \'Claude 3.5 Sonnet\',\n      \'claude-3-7-sonnet-latest\': \'Claude 3.7 Sonnet\',\n    },\n  },\n  GEMINI: {\n    default: \'gemini-2.0-flash\',\n    options: [\'gemini-2.0-flash\', \'gemini-2.0-flash-lite\', \'gemini-2.5-flash-preview-04-17\', \'gemini-2.5-pro-preview-05-06\'] as const,\n    labels: {\n      \'gemini-2.0-flash\': \'Gemini 2.0 Flash\',\n      \'gemini-2.0-flash-lite\': \'Gemini 2.0 Flash Lite\',\n      \'gemini-2.5-flash-preview-04-17\': \'Gemini 2.5 Flash Preview\',\n      \'gemini-2.5-pro-preview-05-06\': \'Gemini 2.5 Pro Preview\',\n    },\n  },\n};\n\nfunction getValidVersion(modelKey: Llm, currentVersion: string | undefined): LlmVersion {\n  const config = MODEL_VERSIONS[modelKey];\n  const validOptions = config.options as readonly LlmVersion[];\n  if (!currentVersion || !validOptions.includes(currentVersion as LlmVersion)) {\n    return config.default;\n  }\n  return currentVersion as LlmVersion;\n}\n\ninterface SettingRowProps {\n  label: string;\n  input: React.ReactNode;\n}\n\nconst SettingRow: React.FC<SettingRowProps> = ({ label, input }) => (\n  <Grid container spacing={1} alignItems="center" sx={{ py: 1 }}>\n    <Grid size={{ xs: 12, sm: 6, md: 4 }}>\n      <Typography variant="body2" fontWeight="normal">\n        {label}\n      </Typography>\n    </Grid>\n    <Grid size={{ xs: 12, sm: 6, md: 8 }}>\n      {input}\n    </Grid>\n  </Grid>\n);\n\ninterface LlmModelSettingRowProps {\n  modelKey: Llm;\n  modelSettings: LlmModelSettings;\n  onToggle: (key: Llm, enabled: boolean) => void;\n  onChangeKey: (key: Llm, value: string) => void;\n  onChangeVersion: (key: Llm, value: LlmVersion) => void;\n}\n\nconst LlmModelSettingRow: React.FC<LlmModelSettingRowProps> = ({\n  modelKey,\n  modelSettings,\n  onToggle,\n  onChangeKey,\n  onChangeVersion,\n}) => {\n  const validVersion = getValidVersion(modelKey, modelSettings.version);\n\n  const renderMenuItems = (): React.ReactNode[] => {\n    const config = MODEL_VERSIONS[modelKey];\n    return config.options.map((version) => {\n      const label = config.labels[version as keyof typeof config.labels];\n      return (\n        <MenuItem\n          key={version}\n          value={version}\n          sx={{ fontWeight: modelSettings.version === version ? \'bold\' : \'normal\' }}\n        >\n          {modelSettings.version === version && <CheckIcon sx={{ mr: 1 }} />}\n          {label}\n        </MenuItem>\n      );\n    });\n  };\n\n  return (\n    <SettingRow\n      label={modelSettings.name}\n      input={(\n        <Grid container spacing={1} alignItems="center">\n          <Grid size="auto">\n            <Switch\n              checked={modelSettings.enabled}\n              onChange={e => onToggle(modelKey, e.target.checked)}\n              slotProps={{\n                input: { \'aria-label\': `Enable ${modelSettings.name}` },\n              }}\n            />\n          </Grid>\n          <Grid size="grow">\n            <TextField\n              disabled={!modelSettings.enabled}\n              fullWidth\n              size="small"\n              value={modelSettings.apiKey}\n              onChange={e => onChangeKey(modelKey, e.target.value)}\n              placeholder={`Enter ${modelSettings.name} API Key`}\n              type="password"\n            />\n          </Grid>\n          <Grid size="auto">\n            <Grid size="auto">\n              <Select\n                value={validVersion}\n                onChange={(e) => {\n                  const newVersion = e.target.value as LlmVersion;\n                  onChangeVersion(modelKey, newVersion);\n                }}\n                disabled={!modelSettings.enabled || !modelSettings.apiKey.trim()}\n                MenuProps={{\n                  disablePortal: true,\n                  PaperProps: {\n                    sx: {\n                      maxHeight: 200,\n                    },\n                  },\n                }}\n              >\n                {renderMenuItems()}\n              </Select>\n            </Grid>\n          </Grid>\n        </Grid>\n      )}\n    />\n  );\n};\n\nconst Settings: React.FC = () => {\n  const id = useId();\n  const viewModel = useViewModel(\'settings\');\n  const { general, llm } = viewModel.state;\n\n  const [generalSettings, setGeneralSettings] = useState<GeneralSettings>(general);\n  const [llmSettings, setLlmSettings] = useState<LlmSettings>(llm);\n\n  useEffect(() => {\n    viewModel.load();\n  }, [viewModel]); // Added viewModel to dependency array if `load` relies on the viewModel instance\n\n  useEffect(() => {\n    setGeneralSettings(general);\n    setLlmSettings(llm);\n  }, [general, llm]);\n\n  const handleGeneralChange = (key: keyof GeneralSettings, value: string | number | AriaMode): void => { // Expanded value type for ariaMode\n    setGeneralSettings(prev => ({\n      ...prev,\n      [key]: value,\n    }));\n  };\n\n  const handleLlmChange = (key: keyof LlmSettings, value: string): void => {\n    setLlmSettings(prev => ({\n      ...prev,\n      [key]: value,\n    }));\n  };\n\n  const handleLlmModelChange = (\n    modelKey: Llm,\n    propKey: keyof LlmModelSettings,\n    value: string | boolean | LlmVersion,\n  ): void => {\n    setLlmSettings(prev => ({\n      ...prev,\n      models: {\n        ...prev.models,\n        [modelKey]: {\n          ...prev.models[modelKey],\n          [propKey]: value,\n        },\n      },\n    }));\n  };\n\n  const handleReset = (): void => {\n    viewModel.reset();\n    const { general, llm } = viewModel.state;\n    setGeneralSettings(general);\n    setLlmSettings(llm);\n  };\n\n  const handleClose = (): void => {\n    viewModel.toggle();\n  };\n\n  const handleSave = (): void => {\n    viewModel.saveAndClose({ general: generalSettings, llm: llmSettings });\n  };\n\n  return (\n    <Dialog\n      id={id}\n      role="dialog"\n      open={true}\n      maxWidth="sm"\n      fullWidth\n      disablePortal\n      disableEnforceFocus\n      onClick={e => e.stopPropagation()}\n      sx={{\n        \'& .MuiDialog-paper\': {\n          zIndex: 9998,\n          maxHeight: \'90vh\',\n        },\n        \'& .MuiDialogContent-root\': {\n          overflow: \'auto\',\n        },\n      }}\n    >\n      <DialogContent>\n        <Grid size="grow">\n          <Typography variant="h6" fontWeight="bold" gutterBottom>\n            Settings\n          </Typography>\n        </Grid>\n\n        {/* General Settings */}\n        <Grid container spacing={0.5}>\n          <Grid size={12}>\n            <SettingRow\n              label="Volume"\n              input={(\n                <Slider\n                  value={generalSettings.volume}\n                  onChange={(_, value) => handleGeneralChange(\'volume\', Number(value))}\n                  min={0}\n                  max={100}\n                  step={1}\n                  valueLabelDisplay="auto"\n                  sx={{\n                    \'& .MuiSlider-valueLabel\': {\n                      backgroundColor: \'primary.main\',\n                      borderRadius: 1,\n                    },\n                  }}\n                />\n              )}\n            />\n          </Grid>\n          <Grid size={12}>\n            <SettingRow\n              label="Outline Color"\n              input={(\n                <TextField\n                  fullWidth\n                  type="color"\n                  size="small"\n                  value={generalSettings.highlightColor}\n                  onChange={e => handleGeneralChange(\'highlightColor\', e.target.value)}\n                />\n              )}\n            />\n          </Grid>\n          <Grid size={12}>\n            <SettingRow\n              label="Braille Display Size"\n              input={(\n                <TextField\n                  fullWidth\n                  type="number"\n                  size="small"\n                  value={generalSettings.brailleDisplaySize}\n                  onChange={e => handleGeneralChange(\'brailleDisplaySize\', Number(e.target.value))}\n                />\n              )}\n            />\n          </Grid>\n          <Grid size={12}>\n            <SettingRow\n              label="Min Frequency (Hz)"\n              input={(\n                <TextField\n                  fullWidth\n                  type="number"\n                  size="small"\n                  value={generalSettings.minFrequency}\n                  onChange={e => handleGeneralChange(\'minFrequency\', Number(e.target.value))}\n                />\n              )}\n            />\n          </Grid>\n          <Grid size={12}>\n            <SettingRow\n              label="Max Frequency (Hz)"\n              input={(\n                <TextField\n                  fullWidth\n                  type="number"\n                  size="small"\n                  value={generalSettings.maxFrequency}\n                  onChange={e => handleGeneralChange(\'maxFrequency\', Number(e.target.value))}\n                />\n              )}\n            />\n          </Grid>\n          <Grid size={12}>\n            <SettingRow\n              label="Autoplay Duration (ms)"\n              input={(\n                <TextField\n                  fullWidth\n                  type="number"\n                  size="small"\n                  value={generalSettings.autoplayDuration}\n                  onChange={e => handleGeneralChange(\'autoplayDuration\', Number(e.target.value))}\n                />\n              )}\n            />\n          </Grid>\n          <Grid size={12}>\n            <SettingRow\n              label="ARIA Mode"\n              input={(\n                <FormControl>\n                  <RadioGroup\n                    row\n                    value={generalSettings.ariaMode}\n                    onChange={e => handleGeneralChange(\'ariaMode\', e.target.value as AriaMode)}\n                  >\n                    <FormControlLabel\n                      value="assertive"\n                      control={<Radio size="small" />}\n                      label="Assertive"\n                    />\n                    <FormControlLabel\n                      value="polite"\n                      control={<Radio size="small" />}\n                      label="Polite"\n                    />\n                  </RadioGroup>\n                </FormControl>\n              )}\n            />\n          </Grid>\n        </Grid>\n\n        <Grid size={12}>\n          <Divider sx={{ py: 0.5 }} />\n        </Grid>\n\n        {/* LLM Settings */}\n        <Grid container spacing={0.5} sx={{ mt: 2 }}>\n          <Grid size={12}>\n            <Typography variant="h6" fontWeight="bold" gutterBottom>\n              LLM Settings\n            </Typography>\n          </Grid>\n\n          {(Object.keys(llmSettings.models) as Llm[]).map((modelKey) => {\n            const model = llmSettings.models[modelKey];\n            return (\n              <Grid size={12} key={modelKey}>\n                <LlmModelSettingRow\n                  modelKey={modelKey}\n                  modelSettings={model}\n                  onToggle={(key, enabled) => handleLlmModelChange(key, \'enabled\', enabled)}\n                  onChangeKey={(key, value) => handleLlmModelChange(key, \'apiKey\', value)}\n                  onChangeVersion={(key, value) => handleLlmModelChange(key, \'version\', value)}\n                />\n              </Grid>\n            );\n          })}\n\n          {/* Expertise Level */}\n          <Grid size={12}>\n            <SettingRow\n              label="Expertise Level"\n              input={(\n                <FormControl fullWidth size="small">\n                  <Select\n                    value={llmSettings.expertiseLevel}\n                    onChange={e => handleLlmChange(\'expertiseLevel\', e.target.value)}\n                  >\n                    <MenuItem value="basic">Basic</MenuItem>\n                    <MenuItem value="intermediate">Intermediate</MenuItem>\n                    <MenuItem value="advanced">Advanced</MenuItem>\n                  </Select>\n                </FormControl>\n              )}\n            />\n          </Grid>\n\n          <Grid size={12}>\n            <Grid container spacing={1} alignItems="flex-start" sx={{ py: 1 }}>\n              <Grid size={12} sx={{ py: 1 }}>\n                <Typography variant="body2" fontWeight="normal">\n                  Custom Instructions\n                </Typography>\n              </Grid>\n              <Grid size={12}>\n                <TextareaAutosize\n                  minRows={3}\n                  maxRows={6}\n                  value={llmSettings.customInstruction}\n                  onChange={e => handleLlmChange(\'customInstruction\', e.target.value)}\n                  style={{\n                    width: \'100%\',\n                    padding: \'8px\',\n                    border: \'1px solid #ccc\',\n                    borderRadius: \'4px\',\n                  }}\n                  placeholder="Enter custom instruction..."\n                />\n              </Grid>\n            </Grid>\n          </Grid>\n        </Grid>\n\n        <Grid size={12}>\n          <Divider sx={{ py: 0.5 }} />\n        </Grid>\n      </DialogContent>\n\n      {/* Footer Actions  */}\n      <Grid\n        container\n        component={DialogActions}\n        alignItems="center"\n      >\n        <Grid size="auto" sx={{ px: 1 }}>\n          <Button variant="text" color="inherit" onClick={handleReset}>\n            Reset\n          </Button>\n        </Grid>\n        <Grid\n          size="grow"\n          container\n          spacing={1}\n          justifyContent="flex-end"\n          sx={{ px: 2, py: 1 }}\n        >\n          <Grid size="auto">\n            <Button variant="outlined" color="inherit" onClick={handleClose}>\n              Close\n            </Button>\n          </Grid>\n          <Grid size="auto">\n            <Button variant="contained" color="primary" onClick={handleSave}>\n              Save & Close\n            </Button>\n          </Grid>\n        </Grid>\n      </Grid>\n    </Dialog>\n  );\n};\n\nexport default Settings;\n',
        }
